     1→import { OpenAI } from "openai";
     2→import { analyzeMoonAspects, extractAspectsWithMotion } from "./aspectMotion";
     3→import {
     4→  calculateChartDignities,
     5→  getSignRuler,
     6→  getSignFromDegrees,
     7→  isDayChart as checkIsDayChart
     8→} from "./horary/dignities";
     9→import { calculateVoidOfCourseMoon } from "./horary/voidOfCourseMoon";
    10→import { analyzeReception, formatReceptionForDisplay } from "./horary/reception";
    11→import { formatTimingForLLM } from "./horary/timing";
