    15→// Enhanced format chart for LLM with aspect motion
    16→function formatChartForLLMWithMotion(reading: HoraryReading): string {
    17→  const chartData = reading.chartData;
    18→  let formattedData = `## Chart Data for Question: "${reading.question}"\n`;
    19→  formattedData += `**Time**: ${new Date(
    20→    reading.timestamp
    21→  ).toLocaleString()}\n`;
    22→
    23→  if (reading.location) {
    24→    formattedData += `**Location**: ${reading.location.latitude.toFixed(
    25→      2
    26→    )}°N, ${reading.location.longitude.toFixed(2)}°W\n\n`;
    27→  }
    28→
    29→  // Calculate essential dignities for all planets
    30→  const sunHouse = getPlanetHouse(chartData.planets.sun.position, chartData.cusps);
    31→  const isDayChartValue = checkIsDayChart(sunHouse);
    32→  const dignities = calculateChartDignities(chartData.planets, isDayChartValue);
    33→
    34→  // Calculate accidental dignities for all planets
    35→  const accidentalDignities = calculateChartAccidentalDignities(chartData.planets, chartData.cusps, isDayChartValue);
    36→
    37→  // Get ascendant for use in house rulers and significator analysis
    38→  const ascendant = chartData.planets.ascendant;
    39→
    40→  // Calculate aspects with motion (will be used in multiple sections)
    41→  const aspectsWithMotion = chartData.aspects && chartData.aspects.length > 0
    42→    ? extractAspectsWithMotion(chartData, chartData.aspects)
    43→    : [];
    44→
    45→  // Format planetary positions with dignities
    46→  formattedData += `### Planetary Positions & Essential Dignities:\n`;
    47→  formattedData += `**Chart Type**: ${isDayChartValue ? 'Day Chart' : 'Night Chart'} (Sun in House ${sunHouse})\n\n`;
    48→
    49→  Object.entries(chartData.planets).forEach(([planet, planetData]) => {
    50→    // Skip angles for dignity calculation
    51→    if (planet === 'ascendant' || planet === 'midheaven') {
    52→      const { sign, degree } = degreesToSignAndDegree(planetData.position);
    53→      formattedData += `- **${
    54→        planet.charAt(0).toUpperCase() + planet.slice(1)
    55→      }**: ${degree.toFixed(2)}° ${sign}\n`;
    56→      return;
    57→    }
    58→
    59→    const { sign, degree } = degreesToSignAndDegree(planetData.position);
    60→    const house = getPlanetHouse(planetData.position, chartData.cusps);
    61→    const rxSymbol = planetData.isRetrograde ? " ℞" : "";
    62→
    63→    // Get dignity info
    64→    const dignity = dignities[planet];
    65→    const dignityInfo = dignity
    66→      ? ` | ${dignity.description} (${dignity.strength}, Score: ${dignity.score})`
    67→      : '';
    68→
    69→    // Get accidental dignity info
    70→    const accDignity = accidentalDignities[planet];
    71→    const accDignityInfo = accDignity
    72→      ? ` | Accidental: ${accDignity.houseType} house, ${accDignity.speedStatus} speed, ${accDignity.lightCondition} (${accDignity.strength}, Score: ${accDignity.totalScore})`
    73→      : '';
    74→
    75→    formattedData += `- **${
    76→      planet.charAt(0).toUpperCase() + planet.slice(1)
    77→    }${rxSymbol}**: ${degree.toFixed(2)}° ${sign} (House ${house})${dignityInfo}${accDignityInfo}\n`;
    78→  });
    79→
    80→  // Format house rulers (using whole sign houses)
    81→  formattedData += `\n### House Rulers (Whole Sign System):\n`;
    82→  if (ascendant) {
    83→    const ascSign = getSignFromDegrees(ascendant.position);
    84→    const signs = ['aries', 'taurus', 'gemini', 'cancer', 'leo', 'virgo', 'libra', 'scorpio', 'sagittarius', 'capricorn', 'aquarius', 'pisces'];
    85→    const ascSignIndex = signs.indexOf(ascSign.sign.toLowerCase());
    86→
    87→    for (let i = 0; i < 12; i++) {
    88→      const houseSign = signs[(ascSignIndex + i) % 12];
    89→      const ruler = getSignRuler(houseSign as any);
    90→      const rulerPlanet = chartData.planets[ruler];
    91→
    92→      if (rulerPlanet) {
    93→        const rulerSign = getSignFromDegrees(rulerPlanet.position);
    94→        const rulerHouse = getPlanetHouse(rulerPlanet.position, chartData.cusps);
    95→        const rulerDignity = dignities[ruler];
    96→        const rulerStrength = rulerDignity ? rulerDignity.strength : 'Unknown';
    97→
    98→        formattedData += `- **House ${i + 1}** (${houseSign.charAt(0).toUpperCase() + houseSign.slice(1)}): `;
    99→        formattedData += `Ruled by ${ruler.charAt(0).toUpperCase() + ruler.slice(1)} `;
   100→        formattedData += `at ${rulerSign.degreeInSign.toFixed(1)}° ${rulerSign.sign.charAt(0).toUpperCase() + rulerSign.sign.slice(1)}, `;
   101→        formattedData += `House ${rulerHouse}, ${rulerStrength}\n`;
   102→      }
   103→    }
   104→  }
   105→
   106→  // Enhanced aspects with motion data
   107→  if (aspectsWithMotion.length > 0) {
   108→    formattedData += `\n### Major Aspects:\n`;
   109→
   110→    aspectsWithMotion.forEach((aspect) => {
   111→      const status = aspect.isApplying
   112→        ? "→ Applying"
   113→        : aspect.isSeparating
   114→        ? "← Separating"
   115→        : "⚮ Stable";
   116→
   117→      formattedData += `- **${aspect.point1Label} ${aspect.aspectLabel} ${aspect.point2Label}** `;
   118→      formattedData += `${status} (orb: ${aspect.currentOrb.toFixed(2)}°)`;
   119→
   120→      if (aspect.timeToExact && aspect.timeToExact < 30) {
   121→        formattedData += ` [Exact in ${aspect.timeToExact.toFixed(1)} days]`;
   122→      } else if (aspect.timeSinceExact && aspect.timeSinceExact < 30) {
   123→        formattedData += ` [Was exact ${aspect.timeSinceExact.toFixed(
   124→          1
   125→        )} days ago]`;
   126→      }
   127→
   128→      if (aspect.isPerfect) {
   129→        formattedData += " **✱ PERFECT**";
   130→      }
   131→
   132→      // Add timing analysis for applying aspects
   133→      if (aspect.isApplying && aspect.timingEstimate) {
   134→        const timing = aspect.timingEstimate;
   135→        formattedData += `\n  **⏱ Timing:** ${timing.signType.charAt(0).toUpperCase() + timing.signType.slice(1)} sign + ${timing.housePlacement.charAt(0).toUpperCase() + timing.housePlacement.slice(1)} house`;
   136→        formattedData += ` → Expect: ${timing.suggestedTimeframes.fastest.value} ${timing.suggestedTimeframes.fastest.unit}`;
   137→        formattedData += ` to ${timing.suggestedTimeframes.slowest.value} ${timing.suggestedTimeframes.slowest.unit}`;
   138→        formattedData += ` (most likely: ${timing.suggestedTimeframes.mostLikely.value} ${timing.suggestedTimeframes.mostLikely.unit})`;
   139→        if (timing.conflictingSignals) {
   140→          formattedData += ` ⚠️ (conflicting timing signals)`;
   141→        }
   142→      }
   143→
   144→      formattedData += "\n";
   145→    });
   146→
   147→    // Special Moon analysis for horary
   148→    const moonAnalysis = analyzeMoonAspects(aspectsWithMotion);
   149→
   150→    if (moonAnalysis.lastSeparatingAspect || moonAnalysis.nextApplyingAspect) {
   151→      formattedData += `\n### Moon's Recent & Next Aspects (Crucial for Horary):\n`;
   152→
   153→      if (moonAnalysis.lastSeparatingAspect) {
   154→        const asp = moonAnalysis.lastSeparatingAspect;
   155→        formattedData += `- **Most Recent**: Moon ${asp.aspectLabel} ${
   156→          asp.point1Key === "moon" ? asp.point2Label : asp.point1Label
   157→        } `;
   158→        formattedData += `(separating, orb: ${asp.currentOrb.toFixed(2)}°)\n`;
   159→      }
   160→
   161→      if (moonAnalysis.nextApplyingAspect) {
   162→        const asp = moonAnalysis.nextApplyingAspect;
   163→        formattedData += `- **Next**: Moon ${asp.aspectLabel} ${
   164→          asp.point1Key === "moon" ? asp.point2Label : asp.point1Label
   165→        } `;
   166→        formattedData += `(applying, orb: ${asp.currentOrb.toFixed(2)}°`;
   167→        if (asp.timeToExact) {
   168→          formattedData += `, exact in ${asp.timeToExact.toFixed(1)} days`;
   169→        }
   170→        formattedData += ")\n";
   171→
   172→        // Add timing estimate for Moon's next aspect if available
   173→        if (asp.timingEstimate) {
   174→          const timing = asp.timingEstimate;
   175→          formattedData += `  **Timing Guidance:** This aspect will perfect in approximately ${timing.suggestedTimeframes.mostLikely.value} ${timing.suggestedTimeframes.mostLikely.unit}`;
   176→          formattedData += ` (range: ${timing.suggestedTimeframes.fastest.value} ${timing.suggestedTimeframes.fastest.unit}`;
   177→          formattedData += ` to ${timing.suggestedTimeframes.slowest.value} ${timing.suggestedTimeframes.slowest.unit}).\n`;
   178→          formattedData += `  ${timing.interpretation}\n`;
   179→        }
   180→      }
   181→    }
   182→  }
   183→
   184→  // Add Void of Course Moon status (CRITICAL for radicality)
   185→  const vocMoon = calculateVoidOfCourseMoon(chartData.planets);
   186→  formattedData += `\n### Void of Course Moon (Critical for Radicality):\n`;
   187→  formattedData += `- **Status**: ${vocMoon.isVoid ? '⚠️ VOID OF COURSE' : '✓ NOT VOID OF COURSE'}\n`;
   188→  formattedData += `- **Current Sign**: ${vocMoon.currentSign} (${vocMoon.degreesUntilNextSign.toFixed(1)}° until ${vocMoon.nextSign})\n`;
   189→  formattedData += `- **Time Until Sign Change**: ${vocMoon.hoursUntilNextSign.toFixed(1)} hours\n`;
   190→
   191→  if (!vocMoon.isVoid && vocMoon.lastAspect) {
   192→    formattedData += `- **Next Aspect Before Sign Change**: Moon will ${vocMoon.lastAspectType} ${vocMoon.lastAspectPlanet?.toUpperCase()} before leaving ${vocMoon.currentSign}\n`;
   193→  }
   194→
   195→  if (vocMoon.isVoid && vocMoon.effectiveInCurrentSign) {
   196→    formattedData += `- **Exception**: Moon is in ${vocMoon.currentSign}, an exception sign where VOC Moon is still effective\n`;
   197→  }
   198→
   199→  formattedData += `- **Interpretation**: ${vocMoon.interpretation}\n`;
   200→
   201→  // Add Part of Fortune
   202→  if (ascendant) {
   203→    const pof = calculatePartOfFortune(
   204→      ascendant.position,
   205→      chartData.planets.sun.position,
   206→      chartData.planets.moon.position,
   207→      chartData.planets,
   208→      chartData.cusps
   209→    );
   210→
   211→    formattedData += `\n### Part of Fortune (Pars Fortunae):\n`;
   212→    formattedData += formatPartOfFortuneForDisplay(pof);
   213→  }
   214→
   215→  // Add significator analysis (which house rulers are involved)
   216→  formattedData += `\n### Significator Analysis:\n`;
   217→
   218→  // Reuse ascendant from house rulers section
   219→  if (ascendant) {
   220→    const ascSign = getSignFromDegrees(ascendant.position);
   221→    const firstHouseRuler = getSignRuler(ascSign.sign.toLowerCase() as any);
   222→    const querentPlanet = chartData.planets[firstHouseRuler];
   223→
   224→    if (querentPlanet) {
   225→      const querentSign = getSignFromDegrees(querentPlanet.position);
   226→      const querentDignity = dignities[firstHouseRuler];
   227→      formattedData += `- **Querent (1st House Ruler)**: ${firstHouseRuler.charAt(0).toUpperCase() + firstHouseRuler.slice(1)} `;
   228→      formattedData += `at ${querentSign.degreeInSign.toFixed(1)}° ${querentSign.sign.charAt(0).toUpperCase() + querentSign.sign.slice(1)} `;
   229→      formattedData += `(${querentDignity?.strength || 'Unknown'}, Score: ${querentDignity?.score || 0})`;
   230→      if (querentPlanet.isRetrograde) {
   231→        formattedData += ` ℞ RETROGRADE - May indicate delays or reversal`;
   232→      }
   233→      formattedData += `\n`;
   234→
   235→      // Find 7th house ruler (descendant = other person/quesited for relationship questions)
   236→      const signs = ['aries', 'taurus', 'gemini', 'cancer', 'leo', 'virgo', 'libra', 'scorpio', 'sagittarius', 'capricorn', 'aquarius', 'pisces'];
   237→      const ascSignIndex = signs.indexOf(ascSign.sign.toLowerCase());
   238→      const seventhHouseSign = signs[(ascSignIndex + 6) % 12];
   239→      const seventhHouseRuler = getSignRuler(seventhHouseSign as any);
   240→      const quesitedPlanet = chartData.planets[seventhHouseRuler];
   241→
   242→      if (quesitedPlanet && seventhHouseRuler !== firstHouseRuler) {
   243→        const quesitedSign = getSignFromDegrees(quesitedPlanet.position);
   244→        const quesitedDignity = dignities[seventhHouseRuler];
   245→        formattedData += `- **Quesited/Other (7th House Ruler)**: ${seventhHouseRuler.charAt(0).toUpperCase() + seventhHouseRuler.slice(1)} `;
   246→        formattedData += `at ${quesitedSign.degreeInSign.toFixed(1)}° ${quesitedSign.sign.charAt(0).toUpperCase() + quesitedSign.sign.slice(1)} `;
   247→        formattedData += `(${quesitedDignity?.strength || 'Unknown'}, Score: ${quesitedDignity?.score || 0})`;
   248→        if (quesitedPlanet.isRetrograde) {
   249→          formattedData += ` ℞ RETROGRADE - May indicate delays or reversal`;
   250→        }
   251→        formattedData += `\n`;
   252→
   253→        // Check if significators aspect each other
   254→        const significatorAspects = aspectsWithMotion.filter(asp =>
   255→          (asp.point1Key === firstHouseRuler && asp.point2Key === seventhHouseRuler) ||
   256→          (asp.point2Key === firstHouseRuler && asp.point1Key === seventhHouseRuler)
   257→        );
   258→
   259→        if (significatorAspects.length > 0) {
   260→          formattedData += `\n**Aspects Between Significators:**\n`;
   261→          significatorAspects.forEach(asp => {
   262→            const status = asp.isApplying ? "APPLYING ➜ Will perfect" : asp.isSeparating ? "SEPARATING ➜ Already happened" : "STABLE";
   263→            formattedData += `  - ${asp.point1Label} ${asp.aspectLabel} ${asp.point2Label} (${status}, orb: ${asp.currentOrb.toFixed(2)}°)\n`;
   264→
   265→            // Check for potential prohibitions
   266→            if (asp.isApplying && asp.timeToExact) {
   267→              formattedData += `    ⏱ Will be exact in ${asp.timeToExact.toFixed(1)} days\n`;
   268→
   269→              // Warning about retrograde planets that might frustrate
   270→              if (querentPlanet.isRetrograde || quesitedPlanet.isRetrograde) {
   271→                formattedData += `    ⚠️ WARNING: One significator is retrograde - check for FRUSTRATION (aspect may not perfect)\n`;
   272→              }
   273→            }
   274→          });
   275→        } else {
   276→          formattedData += `\n**No Direct Aspect Between Significators** - Look for translation of light or collection of light\n`;
   277→        }
   278→
   279→        // Analyze reception between significators
   280→        formattedData += `\n**Reception Between Significators:**\n`;
   281→        const reception = analyzeReception(
   282→          firstHouseRuler as any,
   283→          querentPlanet.position,
   284→          seventhHouseRuler as any,
   285→          quesitedPlanet.position
   286→        );
   287→        formattedData += formatReceptionForDisplay(
   288→          firstHouseRuler,
   289→          seventhHouseRuler,
   290→          reception
   291→        );
   292→        formattedData += `\n`;
   293→      }
   294→    }
   295→  }
   296→
   297→  return formattedData;
   298→}
