    if (settings.provider === 'openrouter-free') {
      const quotaCheck = checkQuota();
      if (!quotaCheck.allowed) {
        throw new Error(`Free tier limit reached: ${quotaCheck.reason}. Please add your own API key in Settings to continue.`);
